package bead

import (
	"context"
	cryptoRand "crypto/rand"
	"encoding/hex"
	"fmt"
	"regexp"
	"sync/atomic"
)

const (
	DefaultIDPrefix = "ddx-"
	MaxIDLength     = 64
	MinIDLength     = 8
)

var idCharsetRe = regexp.MustCompile(`^[a-zA-Z0-9-]+$`)

// ValidateID reports whether id matches the bead identifier contract.
func ValidateID(id string) error {
	if len(id) < MinIDLength || len(id) > MaxIDLength {
		return fmt.Errorf("%w: length %d not in [%d, %d]", ErrInvalidID, len(id), MinIDLength, MaxIDLength)
	}
	if !idCharsetRe.MatchString(id) {
		return fmt.Errorf("%w: charset", ErrInvalidID)
	}
	return nil
}

// IDGenerator produces new bead identifiers.
type IDGenerator interface {
	GenID(ctx context.Context) (string, error)
}

// RandomHexIDGenerator emits a prefixed random hex identifier.
type RandomHexIDGenerator struct {
	Prefix string
	Bytes  int
}

// GenID generates a random hex identifier with the configured prefix.
func (g RandomHexIDGenerator) GenID(ctx context.Context) (string, error) {
	if ctx != nil {
		select {
		case <-ctx.Done():
			return "", ctx.Err()
		default:
		}
	}
	prefix := g.Prefix
	if prefix == "" {
		prefix = DefaultIDPrefix
	}
	numBytes := g.Bytes
	if numBytes <= 0 {
		numBytes = 4
	}
	buf := make([]byte, numBytes)
	if _, err := cryptoRand.Read(buf); err != nil {
		return "", fmt.Errorf("bead: gen id: %w", err)
	}
	id := prefix + hex.EncodeToString(buf)
	if err := ValidateID(id); err != nil {
		return "", err
	}
	return id, nil
}

// SequentialIDGenerator emits monotonically increasing identifiers.
type SequentialIDGenerator struct {
	Prefix  string
	counter atomic.Uint64
}

// GenID generates a zero-padded hex sequence identifier.
func (g *SequentialIDGenerator) GenID(ctx context.Context) (string, error) {
	if ctx != nil {
		select {
		case <-ctx.Done():
			return "", ctx.Err()
		default:
		}
	}
	if g == nil {
		return "", fmt.Errorf("bead: sequential id generator is nil")
	}
	prefix := g.Prefix
	if prefix == "" {
		prefix = DefaultIDPrefix
	}
	n := g.counter.Add(1)
	id := fmt.Sprintf("%s%08x", prefix, n)
	if err := ValidateID(id); err != nil {
		return "", err
	}
	return id, nil
}

// NewIDGenerator returns the default random generator used by the bead
// storage layer.
func NewIDGenerator() IDGenerator {
	return RandomHexIDGenerator{Prefix: DefaultIDPrefix, Bytes: 4}
}

package bead

import (
	"bufio"
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"strings"
	"sync"
	"sync/atomic"
	"testing"
	"time"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// TestMain scrubs all GIT_* environment variables before running tests so
// test subprocesses don't inherit lefthook's GIT_DIR/GIT_WORK_TREE and leak
// into the parent repo's config.
func TestMain(m *testing.M) {
	for _, kv := range os.Environ() {
		if strings.HasPrefix(kv, "GIT_") {
			if idx := strings.IndexByte(kv, '='); idx >= 0 {
				_ = os.Unsetenv(kv[:idx])
			}
		}
	}
	os.Exit(m.Run())
}

func newTestStore(t *testing.T) *Store {
	t.Helper()
	dir := t.TempDir()
	s := NewStore(filepath.Join(dir, ".ddx"))
	require.NoError(t, s.Init())
	return s
}

func newConfiguredStore(t *testing.T, backend string) *Store {
	t.Helper()
	dir := t.TempDir()
	if backend != "" {
		writeStoreConfig(t, dir, backend)
	}
	s := NewStore(filepath.Join(dir, ".ddx"))
	require.NoError(t, s.Init())
	return s
}

func newJSONLStore(t *testing.T) *Store {
	t.Helper()
	return newConfiguredStore(t, BackendJSONL)
}

func writeStoreConfig(t *testing.T, dir string, backend string) {
	t.Helper()
	ddxDir := filepath.Join(dir, ".ddx")
	require.NoError(t, os.MkdirAll(ddxDir, 0o755))
	content := fmt.Sprintf(`version: "1.0"
library:
  path: "./library"
  repository:
    url: "https://github.com/test/repo"
    branch: "main"
bead:
  backend: %s
`, backend)
	require.NoError(t, os.WriteFile(filepath.Join(ddxDir, "config.yaml"), []byte(content), 0o644))
}

func TestInit(t *testing.T) {
	dir := t.TempDir()
	s := NewStore(filepath.Join(dir, ".ddx"))
	require.NoError(t, s.Init())

	_, err := os.Stat(s.File)
	assert.NoError(t, err, "beads.jsonl should exist after init")
}

func TestInitUsesCollectionFile(t *testing.T) {
	dir := t.TempDir()
	s := NewStoreWithCollection(filepath.Join(dir, ".ddx"), "exec-runs")
	require.Equal(t, "exec-runs", s.Collection)
	require.Equal(t, filepath.Join(dir, ".ddx", "exec-runs.jsonl"), s.File)
	require.Equal(t, filepath.Join(dir, ".ddx", "exec-runs.lock"), s.LockDir)
	require.NoError(t, s.Init())

	_, err := os.Stat(s.File)
	assert.NoError(t, err, "collection file should exist after init")
}

func TestNewStore_DefaultsToJSONL(t *testing.T) {
	s := NewStore(filepath.Join(t.TempDir(), ".ddx"))
	assert.Nil(t, s.backend)
}

func TestNewStore_SelectsAxonFromConfig(t *testing.T) {
	tempDir := t.TempDir()
	writeStoreConfig(t, tempDir, BackendAxon)
	t.Setenv(AxonExperimentalEnv, "0")

	s := NewStore(filepath.Join(tempDir, ".ddx"))
	_, ok := s.backend.(*AxonBackend)
	assert.True(t, ok, "bead.backend: axon must select AxonBackend without requiring DDX_AXON_EXPERIMENTAL")
}

func TestWithCollectionNormalizesJSONLExtension(t *testing.T) {
	dir := t.TempDir()
	s := NewStore(filepath.Join(dir, ".ddx"), WithCollection("agent-sessions.jsonl"))
	assert.Equal(t, "agent-sessions", s.Collection)
	assert.Equal(t, filepath.Join(dir, ".ddx", "agent-sessions.jsonl"), s.File)
}

func TestExternalBackendCarriesLogicalCollectionName(t *testing.T) {
	toolDir := t.TempDir()
	writeFakeBackendTool(t, toolDir, "bd")
	writeFakeBackendTool(t, toolDir, "br")
	t.Setenv("PATH", toolDir+string(os.PathListSeparator)+os.Getenv("PATH"))

	for _, tc := range []struct {
		name       string
		backend    string
		collection string
	}{
		{name: "default-bd", backend: "bd", collection: DefaultCollection},
		{name: "exec-runs-bd", backend: "bd", collection: "exec-runs"},
		{name: "agent-sessions-br", backend: "br", collection: "agent-sessions"},
	} {
		t.Run(tc.name, func(t *testing.T) {
			t.Setenv("DDX_BEAD_BACKEND", tc.backend)
			s := NewStore(filepath.Join(t.TempDir(), ".ddx"), WithCollection(tc.collection))
